function PackingList() {
  const [items, setItems] = React.useState([
    {cat:'Clothes',list:[{text:'REPLACE_WITH_ITEM_1',done:false},{text:'Underwear (3)',done:false},{text:'Jacket',done:false}]},
    {cat:'Toiletries',list:[{text:'Toothbrush',done:false},{text:'Shampoo',done:false},{text:'Deodorant',done:false}]},
    {cat:'Tech',list:[{text:'Phone charger',done:false},{text:'Power bank',done:false},{text:'Headphones',done:false}]},
    {cat:'Docs',list:[{text:'Passport',done:false},{text:'Boarding pass',done:false},{text:'Hotel booking',done:false}]}
  ]);

  const toggle = (ci,li)=>{
    setItems(items.map((c,i)=>i===ci?{...c,list:c.list.map((l,j)=>j===li?{...l,done:!l.done}:l)}:c));
  };

  const total = items.reduce((a,c)=>a+c.list.length,0);
  const done = items.reduce((a,c)=>a+c.list.filter(l=>l.done).length,0);

  return (
    <div style={{padding:16,fontFamily:'system-ui',height:'100%',display:'flex',flexDirection:'column'}}>
      <div style={{fontSize:18,fontWeight:700,marginBottom:8}}>Packing List</div>
      <div style={{height:6,background:'#eee',borderRadius:3,marginBottom:12}}>
        <div style={{width:`${(done/total)*100}%`,height:'100%',background:'#34C759',borderRadius:3,transition:'width 0.3s'}}/>
      </div>
      <div style={{fontSize:12,color:'#888',marginBottom:10}}>{done} of {total} packed</div>
      <div style={{flex:1,overflow:'auto'}}>
        {items.map((cat,ci)=> (
          <div key={ci} style={{marginBottom:12}}>
            <div style={{fontSize:13,fontWeight:700,color:'#555',marginBottom:6}}>{cat.cat}</div>
            {cat.list.map((item,li)=> (
              <label key={li} style={{display:'flex',alignItems:'center',gap:8,padding:'4px 0',cursor:'pointer'}}>
                <input type="checkbox" checked={item.done} onChange={()=>toggle(ci,li)}/>
                <span style={{fontSize:13,textDecoration:item.done?'line-through':'none',color:item.done?'#888':'#000'}}>
                  {item.text}
                </span>
              </label>
            ))}
          </div>
        ))}
      </div>
    </div>
  );
}
render(<PackingList/>);
